#include "interface.h"

#include <stdint.h>
#include <string.h>

uint64_t run(const char* const* rows, size_t row_count) {
  uint64_t hash = 1469598103934665603ULL;
  for (size_t i = 0; i < row_count; ++i) {
    const char* row = rows[i];
    // Skip "r" and parse id
    row += 1;
    int id = 0;
    while (*row >= '0' && *row <= '9') {
      id = id * 10 + (*row - '0');
      row++;
    }
    // Skip comma
    row += 1;
    // Skip a
    while (*row != ',') row++;
    // Skip comma
    row += 1;
    // Parse b
    int b = 0;
    while (*row >= '0' && *row <= '9') {
      b = b * 10 + (*row - '0');
      row++;
    }
    // Skip comma
    row += 1;
    // Parse c
    int c = 0;
    while (*row >= '0' && *row <= '9') {
      c = c * 10 + (*row - '0');
      row++;
    }
    // Skip comma
    row += 1;
    // Check flag
    uint64_t v = (uint64_t)(b + c + 20);
    if (strncmp(row, "hot", 3) == 0 && (row[3] == '\0' || row[3] == ',' || row[3] == '\n')) {
      v += 29ULL;
    }
    hash ^= (v + 1ULL);
    hash *= 1099511628211ULL;
  }
  return hash;
}
